text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed_decisions": [
        "릴리스 공개 일정은 '스모크 테스트 통과 시 금요일 15:00 KST'로 확정되었다.",
        "smoke-theme-pack.mjs는 packageName 불일치 발생 시 즉시 무시하지 않고, 우선 패키지 설정 자체를 점검한 뒤 스크립트는 컨트랙트 자체에 문제 가능성이 있을 때만 검토한다.",
        "Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
        "Doyun이 금요일 12:00 KST까지 action_items.md에 failure triage 노트를 작성한다.",
        "Hara가 Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다."
      ],
      "rejected_proposals": [
        "Hara가 제안한 'packageName 불일치 시 smoke-theme-pack.mjs에서 무시 처리' 제안은 기각되었다."
      ],
      "internal_stretch_goals": [
        "수요일 발표/릴리스는 공개 릴리스 목표가 아니라 내부 stretch goal로만 관리한다."
      ]
    },
    "non_decisions": [
      "README 설치 단계 리뷰는 목요일 검토 희망이 제안되었으나, 최종 책임자(Owner)가 지정되지 않았다.",
      "Hara의 tarball 경로 확인 작업은 진행 의향만 확인되었고 구체적 완료 시점은 지정되지 않았다.",
      "내부 stretch goal(수요일) 관련 내용을 릴리스 노트에 반영할지 여부는 미결정이다."
    ],
    "risks": [
      "tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
      "README 설치 절차가 오래되면 릴리스 노트의 사용자 안내가 오해를 유발할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 stretch goal(수요일)을 언급할지 여부를 어떻게 할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유",
      "due": "2026-05-15 10:00 KST",
      "status": "확인됨",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage 노트를 action_items.md에 작성",
      "due": "2026-05-15 12:00 KST",
      "status": "확인됨",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 공유 후 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "확인됨",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README install steps 검토(목표: 목요일 가능 시)",
      "due": "미정",
      "status": "미결정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 스모크 테스트 결과 공유 확인",
      "금요일 12:00 KST까지 triage 노트 작성 여부 및 내용 확인",
      "tarball 경로 확인 결과의 유효성 및 후속 반영 필요사항 점검",
      "최종 릴리스 승인 권한자(오픈 질문) 확정",
      "릴리스 노트 반영 범위(내부 수요일 stretch goal 포함 여부) 결정"
    ],
    "do_not_invent": [
      "고객명, 예산, 보안 사고, 운영 장애, 법적 승인, 소유자명 미기재 항목, 마감일 미기재 항목은 생성하지 않는다.",
      "회의 메모에 없는 추가 제안·결정·위험을 임의로 추가하지 않는다."
    ]
  },
  "non_invention_rules": [
    "명시되지 않은 사실(고객/파트너, 예산, 보안 이슈, 장애, 법무 승인, 미기재 owner/마감일 등)은 절대 생성하지 않는다.",
    "원문에 없는 일정·일정변경을 임의로 단정하지 않는다.",
    "미지정 항목은 '미정', '미지정', '미결정'으로만 표현하고 추정값을 넣지 않는다.",
    "실제 근거 없는 수치·조건(예: 확정 지연 사유, 우선순위 스코어, 확약서)은 기록하지 않는다."
  ]
}
